<?php
namespace common\models;

use jobs\ElearningStoreQueue;
use Yii;
use yii\behaviors\TimestampBehavior;
use yii\db\Expression;
use common\models\base\ElearningStoreCourse as base;

class ElearningStoreCourse extends base
{
    /**
     * @inheritdoc
     */
    public function behaviors()
    {
        return [
            [
                'class' => TimestampBehavior::class,
                'createdAtAttribute' => 'created_at',
                'updatedAtAttribute' => 'updated_at',
                'value' => new Expression('NOW()'),
            ],
        ];
    }

    public function rules()
    {
        return parent::rules();
    }

    public static function getCourseByTikTokProductId($productId, $shopId)
    {
        $elearningStoreCourse = self::find()->where(['tiktok_product_id' => $productId , 'store_id' => $shopId])->one();
        if (!empty($elearningStoreCourse->course_id)) {
            $course = MCourse::findOne($elearningStoreCourse->course_id);
            return $course;
        }
        if (!empty($elearningStoreCourse->combo_id)) {
            $combo = MCombo::findOne($elearningStoreCourse->combo_id);
            return $combo;
        }
        return false;
    }

    public static function syncQueue($storeId, $courseIds)
    {
        foreach ($courseIds as $courseId) {
            $model = ElearningStoreCourse::find()->where(['store_id' => $storeId, 'course_id' => $courseId])->one();
            if (!$model){
                $model = new ElearningStoreCourse();
                $model->store_id = $storeId;
                $model->course_id = $courseId;
                $model->update_by = $_SESSION['admin_id'] ?? 1;
                $model->status = false;
                $model->save(false);
            }
            Yii::$app->queue2->push(new ElearningStoreQueue([
                'id' => $model->id
            ]));
        }
        return true;
    }

    public static function syncComboQueue($storeId, $comboIds)
    {
        foreach ($comboIds as $comboId) {
            $model = ElearningStoreCourse::find()->where(['store_id' => $storeId, 'combo_id' => $comboId])->one();
            if (!$model){
                $model = new ElearningStoreCourse();
                $model->store_id = $storeId;
                $model->combo_id = $comboId;
                $model->update_by = $_SESSION['admin_id'] ?? 1;
                $model->status = false;
                $model->save(false);
            }
            Yii::$app->queue2->push(new ElearningStoreQueue([
                'id' => $model->id
            ]));
        }
        return true;
    }
}

